{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-cross-object-mixed-risk-reconnect-pump-update-plus-separator-placeholder-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "summary": "当前围绕已选中的泵、闪蒸罐及其关联物流生成候选提案，重点处理泵出口压力设定无效、分离器固定压力模式缺少目标压力，以及未连接液相出口的局部问题。",
  "answers": [
    {
      "summary": "针对 pump-13、separator-10 和 separator-liquid-92 提出最小候选补丁，包含一个泵参数修正、一个分离器压力占位补全，以及一个下游连接占位。",
      "issues": [
        {
          "title": "泵出口压力目标低于入口压力",
          "detail": "pump-13 的 outlet_pressure_target_kpa=150，小于入口物流 feed-92 的 pressure_kpa=200，直接触发无效设定。",
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "title": "分离器固定压力模式缺少操作压力目标",
          "detail": "separator-10 处于 fixed 压力模式，但缺少 operating pressure target。",
          "citations": [
            "diag-3",
            "flowdoc-unit-2"
          ]
        },
        {
          "title": "液相出口未连接且路由依赖当前工况",
          "detail": "separator-liquid-92 当前没有下游消费者或导出端，且其路由仍依赖当前泵出口与分离器压力上下文。",
          "citations": [
            "diag-1",
            "diag-5",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "将泵出口压力目标改为高于入口压力的待确认值，并补充效率占位修正",
          "target": {
            "type": "unit",
            "id": "pump-13"
          },
          "rationale": "当前诊断直接指出出口压力目标低于入口压力；同时效率 109 超出推荐范围。为保持补丁最小且可审查，仅提出将出口目标改为高于 200 kPa 的待确认值，并把效率调整为待确认的有效范围内值，而不推断具体工艺设计值。",
          "patch": {
            "parameter_updates": {
              "outlet_pressure_target_kpa": {
                "mode": "replace_with_placeholder",
                "spec_placeholder": {
                  "key": "pump_13_outlet_pressure_target_kpa",
                  "expected_type": "number",
                  "constraints": {
                    "greater_than": 200
                  }
                }
              }
            },
            "parameter_placeholders": [
              {
                "path": "config.efficiency_percent",
                "key": "pump_13_efficiency_percent",
                "expected_type": "number",
                "constraints": {
                  "min": 0,
                  "max": 100
                }
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "confidence": 0.94,
          "citations": [
            "diag-2",
            "diag-4",
            "flowdoc-unit-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为固定压力模式分离器补充操作压力目标占位",
          "target": {
            "type": "unit",
            "id": "separator-10"
          },
          "rationale": "诊断明确表明 separator-10 在 fixed 模式下缺少 operating pressure target。现有入料 pump-outlet-92 为 158 kPa、液相出口为 146 kPa，但不足以唯一确定应采用的设备操作压力，因此仅补充待确认占位。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.operating_pressure_target_kpa",
                "key": "separator_10_operating_pressure_target_kpa",
                "expected_type": "number",
                "constraints": {
                  "greater_than": 0
                }
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "confidence": 0.96,
          "citations": [
            "diag-3",
            "flowdoc-unit-2",
            "flowdoc-stream-2",
            "flowdoc-stream-3"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为未连接液相出口添加下游连接占位",
          "target": {
            "type": "stream",
            "id": "separator-liquid-92"
          },
          "rationale": "separator-liquid-92 直接存在未连接错误，但诊断同时指出其最终路由依赖当前泵出口与分离器压力上下文。在证据不足下，不指定具体去向，只建议添加待确认的下游消费者或导出端连接占位。",
          "patch": {
            "connection_placeholder": {
              "stream_id": "separator-liquid-92",
              "endpoint": "target",
              "allowed_target_types": [
                "unit",
                "export_sink"
              ],
              "key": "separator_liquid_92_downstream_target"
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "confidence": 0.87,
          "citations": [
            "diag-1",
            "diag-5",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        }
      ]
    }
  ],
  "citations": [
    {
      "id": "diag-1",
      "kind": "diagnostic",
      "code": "STREAM_DISCONNECTED",
      "target_type": "stream",
      "target_id": "separator-liquid-92"
    },
    {
      "id": "diag-2",
      "kind": "diagnostic",
      "code": "PUMP_OUTLET_PRESSURE_TARGET_INVALID",
      "target_type": "unit",
      "target_id": "pump-13"
    },
    {
