      "target_type": "unit",
      "target_id": "separator-10"
    },
    {
      "id": "diag-4",
      "kind": "diagnostic",
      "code": "UNIT_PARAMETER_OUT_OF_RANGE",
      "target_type": "unit",
      "target_id": "pump-13"
    },
    {
      "id": "diag-5",
      "kind": "diagnostic",
      "code": "DOWNSTREAM_STATE_DEPENDENT",
      "target_type": "stream",
      "target_id": "separator-liquid-92"
    },
    {
      "id": "flowdoc-stream-1",
      "kind": "artifact",
      "artifact_name": "flowsheet_document",
      "entity_type": "stream",
