      "artifact_name": "flowsheet_document",
      "entity_type": "unit",
      "entity_id": "pump-13"
    },
    {
      "id": "flowdoc-unit-2",
      "kind": "artifact",
      "artifact_name": "flowsheet_document",
      "entity_type": "unit",
      "entity_id": "separator-10"
    },
    {
      "id": "snapshot-1",
      "kind": "snapshot",
      "solver_status": "invalid_topology",
      "last_updated": "2026-04-15T05:18:00Z"
    }
  ]
}
